import os, sqlite3
from contextlib import AbstractContextManager

class Writer(AbstractContextManager):
    def __init__(self, path):
        self._path = path
        self._conn = None
        self._expected = 0

    def __enter__(self):
        self._conn = sqlite3.connect(self._path)
        self._conn.execute("CREATE TABLE IF NOT EXISTS t(id INTEGER PRIMARY KEY)")
        return self

    def __exit__(self, exc_type, exc, tb):
        # BUG: swallowing any exception — disk-quota / OSError flows silently
        # through and later verification sees partial write => RuntimeError.
        try:
            if self._conn:
                self._conn.close()
        finally:
            return True

    def write(self, row):
        self._conn.execute("INSERT INTO t VALUES (?)", (row,))
        self._conn.commit()
        self._expected += 1

class Processor:
    def __init__(self, w: Writer):
        self._w = w
        self._expected = 0

    def run_batch(self, batch_id, rows):
        self._expected = len(rows)
        with self._w as w:
            for r in rows:
                w.write(r)
        self._verify_all_written(batch_id)

    def _verify_all_written(self, batch_id):
        import sqlite3
        c = sqlite3.connect(self._w._path)
        found = c.execute("SELECT COUNT(*) FROM t").fetchone()[0]
        if found != self._expected:
            raise RuntimeError(
                f"batch {batch_id!r}: expected {self._expected} rows, found {found}"
            )

if __name__ == '__main__':
    w = Writer('/tmp/x.db')
    Processor(w).run_batch('b-2026-04-21', list(range(10000)))
